export function normalizeStr(s: string): string {
  return s.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim();
}

export function matchesArea(questionSubject: string, selectedArea: string): boolean {
  if (selectedArea === 'Todas') return true;
  const normArea = normalizeStr(selectedArea);
  const normSubj = normalizeStr(questionSubject);
  if (normSubj === normArea) return true;
  const AREA_ALIASES: Record<string,string[]> = {
    'matematica': ['matematica'],
    'matematica financeira': ['matematica financeira'],
    'ciencias': ['biologia', 'quimica', 'fisica'],
    'financas pessoais': ['financas pessoais', 'investimentos', 'matematica financeira'],
    'cpa-20': ['investimentos', 'matematica financeira', 'financas pessoais'],
  };
  const aliases = AREA_ALIASES[normArea] || [];
  return aliases.includes(normSubj);
}

export function getQuestionsByArea(area: string): Question[] {
  if (area === 'Todas') return questionBank;
  return questionBank.filter(q => matchesArea(q.subject, area));
}
